package com.odde.doughnut.services;

import com.odde.doughnut.entities.MemoryTracker;
import com.odde.doughnut.entities.Note;
import com.odde.doughnut.entities.User;
import com.odde.doughnut.entities.UserToken;
import com.odde.doughnut.entities.repositories.MemoryTrackerRepository;
import com.odde.doughnut.entities.repositories.NoteRepository;
import com.odde.doughnut.entities.repositories.UserRepository;
import com.odde.doughnut.entities.repositories.UserTokenRepository;
import com.odde.doughnut.factoryServices.EntityPersister;
import com.odde.doughnut.utils.TimestampOperations;
import java.sql.Timestamp;
import java.time.ZoneId;
import java.util.List;
import java.util.Optional;
import java.util.stream.Stream;
import org.springframework.stereotype.Service;

@Service
public class UserService {
  private final NoteRepository noteRepository;
  private final MemoryTrackerRepository memoryTrackerRepository;
  private final EntityPersister entityPersister;
  private final UserRepository userRepository;
  private final UserTokenRepository userTokenRepository;

  public UserService(
      NoteRepository noteRepository,
      MemoryTrackerRepository memoryTrackerRepository,
      EntityPersister entityPersister,
      UserRepository userRepository,
      UserTokenRepository userTokenRepository) {
    this.noteRepository = noteRepository;
    this.memoryTrackerRepository = memoryTrackerRepository;
    this.entityPersister = entityPersister;
    this.userRepository = userRepository;
    this.userTokenRepository = userTokenRepository;
  }

  public void setDailyAssimilationCount(User user, Integer count) {
    user.setDailyAssimilationCount(count);
    entityPersister.merge(user);
  }

  public void setSpaceIntervals(User user, String spaceIntervals) {
    user.setSpaceIntervals(spaceIntervals);
    entityPersister.merge(user);
  }

  public int getUnassimilatedNoteCount(User user) {
    return noteRepository.countByOwnershipWhereThereIsNoMemoryTracker(
        user.getId(), user.getOwnership().getId());
  }

  public Stream<Note> getUnassimilatedNotes(User user) {
    return noteRepository.findByOwnershipWhereThereIsNoMemoryTracker(
        user.getId(), user.getOwnership().getId());
  }

  public List<MemoryTracker> getRecentMemoryTrackers(User user, Timestamp since) {
    return memoryTrackerRepository.findAllByUserAndAssimilatedAtGreaterThan(user.getId(), since);
  }

  public Stream<MemoryTracker> getMemoryTrackersNeedToRepeat(
      User user, Timestamp currentUTCTimestamp, ZoneId timeZone) {
    final Timestamp timestamp = TimestampOperations.alignByHalfADay(currentUTCTimestamp, timeZone);
    return memoryTrackerRepository.findAllByUserAndNextRecallAtLessThanEqualOrderByNextRecallAt(
        user.getId(), timestamp);
  }

  public List<MemoryTracker> getMemoryTrackersFor(User user, Note note) {
    if (user == null) return List.of();
    return memoryTrackerRepository.findByUserAndNote(user.getId(), note.getId());
  }

  public void removeMemoryTrackersForReassimilation(User user, Note note) {
    List<MemoryTracker> trackers =
        memoryTrackerRepository.findByUserAndNote(user.getId(), note.getId());
    Timestamp now = new Timestamp(System.currentTimeMillis());
    for (MemoryTracker tracker : trackers) {
      tracker.setDeletedAt(now);
      memoryTrackerRepository.save(tracker);
    }
  }

  public Optional<User> findUserByToken(String token) {
    UserToken usertoken = userTokenRepository.findByToken(token);
    if (usertoken == null) {
      return Optional.empty();
    }
    return userRepository.findById(usertoken.getUserId());
  }

  public Optional<UserToken> findTokenByToken(String token) {
    return Optional.ofNullable(userTokenRepository.findByToken(token));
  }

  public Optional<List<UserToken>> findTokensByUser(Integer id) {
    List<UserToken> usertokens = userTokenRepository.findByUserId(id);
    return Optional.ofNullable(usertokens);
  }

  public Optional<UserToken> findTokenByTokenId(Integer id) {
    return userTokenRepository.findById(id);
  }

  public void deleteToken(Integer tokenId) {
    userTokenRepository.deleteById(tokenId);
  }
}

package com.odde.doughnut.testability.builders;

import com.odde.doughnut.entities.*;
import com.odde.doughnut.testability.EntityBuilder;
import com.odde.doughnut.testability.MakeMe;
import java.sql.Timestamp;

public class MemoryTrackerBuilder extends EntityBuilder<MemoryTracker> {

  public MemoryTrackerBuilder(MemoryTracker memoryTracker, MakeMe makeMe) {
    super(makeMe, memoryTracker);
    assimilatedAt(makeMe.aTimestamp().of(0, 0).please());
  }

  public MemoryTrackerBuilder by(User user) {
    entity.setUser(user);
    return this;
  }

  public MemoryTrackerBuilder assimilatedAt(Timestamp assimilatedTimestamp) {
    entity.setAssimilatedAt(assimilatedTimestamp);
    entity.setLastRecalledAt(assimilatedTimestamp);
    entity.setNextRecallAt(assimilatedTimestamp);
    return this;
  }

  public MemoryTrackerBuilder afterNthStrictRecall(Integer recallDone) {
    for (int i = 0; i < recallDone; i++) {
      entity.recalledSuccessfully(entity.getNextRecallAt(), null);
    }
    return this;
  }

  @Override
  protected void beforeCreate(boolean needPersist) {}

  public MemoryTrackerBuilder forgettingCurveAndNextRecallAt(float value) {
    entity.setForgettingCurveIndex(value);
    entity.setNextRecallAt(entity.calculateNextRecallAt());
    return this;
  }

  public MemoryTrackerBuilder removedFromTracking() {
    entity.setRemovedFromTracking(true);
    return this;
  }

  public MemoryTrackerBuilder nextRecallAt(Timestamp timestamp) {
    entity.setNextRecallAt(timestamp);
    return this;
  }

  public MemoryTrackerBuilder spelling() {
    entity.setSpelling(true);
    return this;
  }
}

package com.odde.doughnut.entities.repositories;

import com.odde.doughnut.entities.MemoryTracker;
import java.sql.Timestamp;
import java.util.List;
import java.util.stream.Stream;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.CrudRepository;
import org.springframework.data.repository.query.Param;

public interface MemoryTrackerRepository extends CrudRepository<MemoryTracker, Integer> {
  @Query(
      value =
          "SELECT rp.* FROM memory_tracker rp "
              + " WHERE rp.user_id = :userId "
              + "   AND rp.assimilated_at > :since "
              + "   AND rp.removed_from_tracking IS FALSE "
              + "   AND rp.deleted_at IS NULL",
      nativeQuery = true)
  List<MemoryTracker> findAllByUserAndAssimilatedAtGreaterThan(
      @Param("userId") Integer userId, @Param("since") Timestamp since);

  @Query(value = "SELECT count(*) " + byUserIdFrom, nativeQuery = true)
  int countByUserNotRemoved(@Param("userId") Integer userId);

  @Query(
      value =
          "SELECT rp.* "
              + byUserIdFrom
              + " AND rp.next_recall_at <= :nextRecallAt ORDER BY rp.next_recall_at, IFNULL(rp.spelling, 0) DESC",
      nativeQuery = true)
  Stream<MemoryTracker> findAllByUserAndNextRecallAtLessThanEqualOrderByNextRecallAt(
      @Param("userId") Integer userId, @Param("nextRecallAt") Timestamp nextRecallAt);

  @Query(
      value =
          "SELECT rp.* FROM memory_tracker rp "
              + " WHERE rp.user_id = :userId "
              + "   AND rp.deleted_at IS NULL "
              + "   AND rp.note_id = :noteId",
      nativeQuery = true)
  List<MemoryTracker> findByUserAndNote(Integer userId, @Param("noteId") Integer noteId);

  @Query(
      value =
          "SELECT rp.* FROM memory_tracker rp "
              + byUserIdWhere
              + " ORDER BY rp.assimilated_at DESC LIMIT 100",
      nativeQuery = true)
  List<MemoryTracker> findLast100ByUser(@Param("userId") Integer userId);

  @Query(
      value =
          "SELECT rp.* FROM memory_tracker rp "
              + byUserIdWhere
              + " AND rp.last_recalled_at IS NOT NULL "
              + " ORDER BY rp.last_recalled_at DESC LIMIT 500",
      nativeQuery = true)
  List<MemoryTracker> findLast100RecalledByUser(@Param("userId") Integer userId);

  List<MemoryTracker> findByNote_IdIn(List<Integer> noteIds);

  String byUserIdFrom =
      " FROM memory_tracker rp "
          + " WHERE rp.user_id = :userId "
          + "   AND rp.removed_from_tracking IS FALSE "
          + "   AND rp.deleted_at IS NULL ";

  String byUserIdWhere =
      " WHERE rp.user_id = :userId "
          + "   AND rp.removed_from_tracking IS FALSE "
          + "   AND rp.deleted_at IS NULL ";

  @Query(
      value =
          "SELECT MAX(rp.assimilated_at) FROM memory_tracker rp "
              + " WHERE rp.user_id = :userId "
              + "   AND rp.deleted_at IS NULL",
      nativeQuery = true)
  Timestamp findLastAssimilationTimeByUser(@Param("userId") Integer userId);

  @Query(
      value =
          "SELECT MAX(rp.last_recalled_at) FROM memory_tracker rp "
              + " WHERE rp.user_id = :userId "
              + "   AND rp.deleted_at IS NULL",
      nativeQuery = true)
  Timestamp findLastRecallTimeByUser(@Param("userId") Integer userId);

  @Query(
      value =
          "SELECT COUNT(*) FROM memory_tracker rp "
              + " WHERE rp.user_id = :userId "
              + "   AND rp.deleted_at IS NULL",
      nativeQuery = true)
  long countByUser(@Param("userId") Integer userId);
}

package com.odde.doughnut.entities;

import com.fasterxml.jackson.annotation.JsonIgnore;
import com.fasterxml.jackson.annotation.JsonProperty;
import com.odde.doughnut.controllers.dto.FolderTrailSegments;
import com.odde.doughnut.utils.TimestampOperations;
import jakarta.persistence.CascadeType;
import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.JoinColumn;
import jakarta.persistence.ManyToOne;
import jakarta.persistence.Table;
import jakarta.validation.constraints.NotNull;
import java.sql.Timestamp;
import java.util.List;
import lombok.Getter;
import lombok.Setter;

@Entity
@Table(name = "memory_tracker")
public class MemoryTracker extends EntityIdentifiedByIdOnly {
  public static MemoryTracker buildMemoryTrackerForNote(Note note) {
    MemoryTracker entity = new MemoryTracker();
    entity.setNote(note);
    return entity;
  }

  @Override
  public String toString() {
    return "MemoryTracker{" + "id=" + id + '}';
  }

  @ManyToOne
  @JoinColumn(name = "note_id")
  @Getter
  @Setter
  @NotNull
  private Note note;

  @ManyToOne(cascade = CascadeType.PERSIST)
  @JoinColumn(name = "user_id", referencedColumnName = "id")
  @JsonIgnore
  @Getter
  @Setter
  private User user;

  @Column(name = "last_recalled_at")
  @Getter
  @Setter
  private Timestamp lastRecalledAt;

  @Column(name = "next_recall_at")
  @Getter
  @Setter
  @NotNull
  private Timestamp nextRecallAt;

  @Column(name = "assimilated_at")
  @Getter
  @Setter
  private Timestamp assimilatedAt;

  @Column(name = "recall_count")
  @Getter
  @Setter
  private Integer recallCount = 0;

  @Column(name = "forgetting_curve_index")
  @Getter
  @Setter
  private Float forgettingCurveIndex = ForgettingCurve.DEFAULT_FORGETTING_CURVE_INDEX;

  @Column(name = "removed_from_tracking")
  @Getter
  @Setter
  private Boolean removedFromTracking = false;

  @Column(name = "spelling")
  @Getter
  @Setter
  private Boolean spelling = false;

  @Column(name = "deleted_at")
  @JsonIgnore
  @Getter
  @Setter
  private Timestamp deletedAt;

  private MemoryTracker() {}

  public Timestamp calculateNextRecallAt() {
    return TimestampOperations.addHoursToTimestamp(
        getLastRecalledAt(), forgettingCurve().getRepeatInHours());
  }

  private ForgettingCurve forgettingCurve() {
    return new ForgettingCurve(getUser().getSpacedRepetitionAlgorithm(), getForgettingCurveIndex());
  }

  public void recallFailed(Timestamp currentUTCTimestamp) {
    setForgettingCurveIndex(forgettingCurve().failed());
    setNextRecallAt(TimestampOperations.addHoursToTimestamp(currentUTCTimestamp, 12));
  }

  public void recalledSuccessfully(Timestamp currentUTCTimestamp, Integer thinkingTimeMs) {
    long delayInHours =
        TimestampOperations.getDiffInHours(currentUTCTimestamp, calculateNextRecallAt());

    setForgettingCurveIndex(forgettingCurve().succeeded(delayInHours, thinkingTimeMs));

    setLastRecalledAt(currentUTCTimestamp);
    setNextRecallAt(calculateNextRecallAt());
  }

  public void markAsRecalled(
      Timestamp currentUTCTimestamp, boolean successful, Integer thinkingTimeMs) {
    setRecallCount(getRecallCount() + 1);
    if (successful) {
      recalledSuccessfully(currentUTCTimestamp, thinkingTimeMs);
    } else {
      recallFailed(currentUTCTimestamp);
    }
  }

  @JsonIgnore
  public boolean isActive() {
    return deletedAt == null && !Boolean.TRUE.equals(removedFromTracking);
  }

  @JsonProperty
  public List<Folder> getAncestorFolders() {
    Note n = getNote();
    if (n == null) {
      return List.of();
    }
    return FolderTrailSegments.fromRootToContainingFolder(n);
  }
}

};

